    # We need shortest paths from every node that could be in the tree to every destination
    # For efficiency, compute shortest paths from src to all nodes, and
    # from all nodes to all destinations (reverse Dijkstra)

    # Forward: shortest path cost from src to all nodes
    try:
        src_distances, src_paths = nx.single_source_dijkstra(h, src, weight='cost')
    except Exception:
