    best_cost = float('inf')
    best_edges = None

    try:
        src_dist, src_paths = nx.single_source_dijkstra(h, src, weight='cost')
    except Exception:
        return None

    for hub in h.nodes():
        if hub not in src_dist:
            continue

        try:
            hub_dist, hub_paths = nx.single_source_dijkstra(h, hub, weight='cost')
        except Exception:
            continue

        all_edges = set()
        reachable = True

        # Add src -> hub path edges
        hub_path = src_paths[hub]
        for i in range(len(hub_path) - 1):
            all_edges.add((hub_path[i], hub_path[i + 1]))

        # Add hub -> dst path edges
        for dst in dsts:
            if dst not in hub_dist:
                reachable = False
                break
            dst_path = hub_paths[dst]
            for i in range(len(dst_path) - 1):
                all_edges.add((dst_path[i], dst_path[i + 1]))

        if not reachable:
            continue

        total_edge_cost = sum(h[u][v]['cost'] for u, v in all_edges)
        if total_edge_cost < best_cost:
            best_cost = total_edge_cost
            best_edges = all_edges

    return best_edges


def _local_search(src, dsts, h, tree_edges):
    """Local search: try re-routing each destination through alternative paths"""
    best_edges = set(tree_edges)
    best_cost = sum(h[u][v]['cost'] for u, v in best_edges)
    improved = True
    max_iters = 10

    while improved and max_iters > 0:
        improved = False
        max_iters -= 1
        for dst in dsts:
            # Build tree graph
            tree_graph = nx.DiGraph()
            for u, v in best_edges:
                tree_graph.add_edge(u, v)

            # Find edges used by other destinations
            other_dsts = [d for d in dsts if d != dst]
            edges_used_by_others = set()
            for other_dst in other_dsts:
                try:
                    other_path = nx.shortest_path(tree_graph, src, other_dst)
                    for i in range(len(other_path) - 1):
                        edges_used_by_others.add((other_path[i], other_path[i + 1]))
                except nx.NetworkXNoPath:
                    pass

            # Try alternative path: edges used by others are free
            G_mod = h.copy()
            for u, v in edges_used_by_others:
                if G_mod.has_edge(u, v):
                    G_mod[u][v]['cost'] = 0

            try:
                alt_path = nx.dijkstra_path(G_mod, src, dst, weight='cost')
            except (nx.NetworkXNoPath, nx.NodeNotFound):
                continue

            # Compute new tree edges
            new_edges = set(edges_used_by_others)
            for i in range(len(alt_path) - 1):
                new_edges.add((alt_path[i], alt_path[i + 1]))

            # Verify all destinations reachable
            new_graph = nx.DiGraph()
            for u, v in new_edges:
                new_graph.add_edge(u, v)

            all_reachable = True
            for d in dsts:
                if not nx.has_path(new_graph, src, d):
                    all_reachable = False
                    break

            if not all_reachable:
                continue

            new_cost = sum(h[u][v]['cost'] for u, v in new_edges)
            if new_cost < best_cost - 1e-9:
                best_cost = new_cost
                best_edges = new_edges
                improved = True
                break

    return best_edges


def _build_fallback_topology(src, dsts, h, G, bc_topology, num_partitions):
    """Fallback to simple shortest path per destination"""
    for dst in dsts:
        try:
            path = nx.dijkstra_path(h, src, dst, weight='cost')
            for i in range(len(path) - 1):
                s, t = path[i], path[i + 1]
                for j in range(num_partitions):
                    bc_topology.append_dst_partition_path(dst, j, [s, t, G[s][t]])
        except Exception:
            pass
    return bc_topology


class SingleDstPath(Dict):
    partition: int
    edges: List[List]  # [[src, dst, edge data]]


class BroadCastTopology:
    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, SingleDstPath] = None):
        self.src = src  # single str
        self.dsts = dsts  # list of strs
        self.num_partitions = num_partitions

        # dict(dst) --> dict(partition) --> list(nx.edges)
        # example: {dst1: {partition1: [src->node1, node1->dst1], partition 2: [src->dst1]}}
        if paths is not None:
            self.paths = paths
            self.set_graph()
        else:
            self.paths = {dst: {str(i): None for i in range(num_partitions)} for dst in dsts}

    def get_paths(self):
        print(f"now the set path is: {self.paths}")
        return self.paths

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def set_dst_partition_paths(self, dst: str, partition: int, paths: List[List]):
        """
        Set paths for partition = partition to reach dst
        """
        partition = str(partition)
        self.paths[dst][partition] = paths

    def append_dst_partition_path(self, dst: str, partition: int, path: List):
        """
        Append path for partition = partition to reach dst
        """
        partition = str(partition)
        if self.paths[dst][partition] is None:
            self.paths[dst][partition] = []
        self.paths[dst][partition].append(path)

def make_nx_graph(cost_path=None, throughput_path=None, num_vms=1):
    """
